function onBackTopClick(): void {
  // 先把控制位置的变量同步为当前实际位置，然后再变回 0，强制触发 Vue 属性变更响应
  scrollViewScrollTop.value = scrollTop.value
  setTimeout(() => {
    scrollViewScrollTop.value = 0
  }, 20)
}

